void CheckDevice(int id)
{
    Print($"查询设备{id}...");
    var d = Serial.ReadLine();
    if (d != null) Print($"设备{id}: {d}");
    else Print($"设备{id}: 无响应");
}
Serial.Open();
for (int i = 1; i <= 3; i++) CheckDevice(i);
